+.date-chip.small { width: 37px; padding: 0; }
+.date-range { width: 360px; height: 32px; border: 1px solid #d5dbe6; border-radius: 3px; background: #f4f7fb; display: flex; align-items: center; gap: 18px; color: #a9b2c1; padding: 0 12px; }
+.date-range em { font-style: normal; min-width: 86px; text-align: center; }
+.date-range b { font-weight: 400; color: #9fa9b8; }
+.sms-query-actions { position: absolute; left: 50%; bottom: 14px; transform: translateX(-50%); display: flex; gap: 6px; }
+.sms-toolbar { height: 40px; display: flex; align-items: center; gap: 10px; padding: 0 10px; background: #c8d1e6; border: 1px solid #c5cfdf; border-bottom: 0; }
+.sms-tool-text { height: 30px; border: 0; background: transparent; color: #263f70; display: inline-flex; align-items: center; gap: 5px; }
+.sms-pagination { margin-left: auto; }
+.sms-actions { color: #284c86; letter-spacing: 9px; white-space: nowrap; }
+.sms-long-text { white-space: normal; line-height: 1.7; display: block; padding: 0 10px; text-align: left; }
+.yes-tag { display: inline-flex; align-items: center; justify-content: center; min-width: 31px; height: 24px; border: 1px solid #cdebbc; background: #eaf9df; color: #4daf2c; border-radius: 4px; }
+.record-query .query-field { width: 430px; }
+.record-query .query-field > span { width: 100px; }
+.sms-split { display: flex; min-height: calc(100vh - 92px); background: #fff; border-top: 1px solid #d3d8e4; }
+.sms-tree-panel { width: 278px; flex: 0 0 278px; border-right: 1px solid #d8dde7; background: #fff; min-height: 100%; }
+.tree-search { height: 45px; display: flex; align-items: center; gap: 7px; padding: 7px 8px; border-bottom: 1px solid #e1e5ed; }
+.tree-search button { width: 30px; height: 30px; border: 1px solid #d4d9e4; background: #fff; color: #405987; border-radius: 3px; }
+.tree-search input { flex: 1; min-width: 0; height: 30px; border: 1px solid #d4d9e4; border-radius: 3px; padding: 0 8px; color: #606b7c; }
+.tree-search svg { color: #3c5482; }
+.tree-list { height: calc(100vh - 140px); overflow: hidden; padding: 8px 10px; font-size: 14px; }
+.tree-item { height: 27px; display: flex; align-items: center; gap: 4px; color: #34415a; white-space: nowrap; }
+.tree-item-name { min-width: 0; overflow: hidden; text-overflow: ellipsis; }
+.tree-sort-toggle { margin-left: auto; padding-right: 6px; display: inline-flex; align-items: center; gap: 4px; font-size: 12px; font-weight: 400; color: #53627a; }
+.tree-sort-toggle input { width: 13px; height: 13px; margin: 0; }
+.tree-expander { flex: 0 0 auto; color: #7c8799; }
+.tree-expander[data-muted="true"] { color: #b6becb; }
+.tree-node-icon { flex: 0 0 auto; }
+.tree-node-icon.folder-icon { color: #7d8899; }
+.tree-node-icon.file-icon { color: #8792a2; }
+.tree-item.folder { font-weight: 700; color: #213b6a; }
+.tree-item.child { padding-left: 24px; }
+.sms-split-main { flex: 1; min-width: 0; background: #fff; overflow: auto; }
+.sms-tabs { height: 43px; display: flex; align-items: flex-end; gap: 4px; padding: 0 14px; background: #edf2fa; border-bottom: 1px solid #cbd3e2; }
+.sms-tabs button { height: 34px; min-width: 86px; border: 1px solid #cad2e2; background: #fff; color: #5d6574; border-radius: 5px 5px 0 0; }
+.sms-tabs button.active { background: #d6def1; color: #173a71; font-weight: 700; }
+.switch-copy { display: inline-flex; align-items: center; gap: 7px; color: #5e6670; }
+.switch-copy i { width: 34px; height: 18px; border-radius: 10px; background: #d7dce5; display: inline-block; position: relative; }
+.switch-copy i::after { content: ''; position: absolute; left: 2px; top: 2px; width: 14px; height: 14px; background: #fff; border-radius: 50%; box-shadow: 0 1px 2px rgba(0,0,0,.18); }
+.sms-split .sms-toolbar { border-left: 0; border-right: 0; }
+.sms-split .data-table { min-width: 960px; }
